/*!
 * JEF DBCS table — derived from IBM-1390_P110-2003 (Unicode-ICU).
 * Format: base64 of [b1, b2, cp_hi, cp_lo] per entry. BMP-only.
 * Parsed into a Map at load time.
 */
(function (global) {
  var DATA = "";
  var bin = atob(DATA);
  var map = new Map();
  for (var i = 0; i + 3 < bin.length; i += 4) {
    var key = (bin.charCodeAt(i) << 8) | bin.charCodeAt(i + 1);
    var val = (bin.charCodeAt(i + 2) << 8) | bin.charCodeAt(i + 3);
    map.set(key, val);
  }
  global.JEF_DBCS_MAP = map;
})(typeof window !== 'undefined' ? window : globalThis);
